sql:
SELECT SUM(sale_amount) AS total_sales_amount
FROM sales
WHERE sale_date >= '2023-05-01';

SELECT SUM(total_sales) AS total_sales_amount
FROM sales_report
WHERE agency_code = (SELECT agency_code FROM agencies WHERE agency_name = 'Custom to Business');

SELECT agent_id, SUM(sale_amount) AS total_sales
FROM agent_sales
GROUP BY agent_id;

SELECT total_sales
FROM sales_report
WHERE report_id = 0;

external_knowledge:
- 'crowning jewels' refers to the top-selling products for each agency; 
- 'bring home the most bacon' refers to generating the highest total sales; 
- 'crown them as the top sellers' means ranking the products as the highest-selling within each agency.
